Argumentos: {"content": "// RenderCache v0.16 — Pre-sort estático de entidades por capa [FASE 8]
//
// En vez de ordenar/sortear entidades cada frame, las entidades se
// insertan en el bucket de capa correcto al crearse.
// El render solo itera los buckets en orden (0..=5), sin sort.
//
// FASE 8:
// - sprite_index en RenderCacheEntry para renderizado con texturas
// - zone_sprite y building_sprite mappings
// - rebuild_from_world propaga sprite_index desde ECS

use crate::ecs::{BuildingType, ZoneType, Position, Renderable, ZoneComponent};

/// Capas de renderizado (orden back-to-front)
pub const LAYER_TERRAIN: u8 = 0;
pub const LAYER_ZONES: u8 = 1;
pub const LAYER_BUILDINGS: u8 = 2;
pub const LAYER_CONSTRUCTION: u8 = 3;
pub const LAYER_TRAFFIC: u8 = 4;
pub const LAYER_UI: u8 = 5;
pub const NUM_RENDER_LAYERS: usize = 6;

/// Entrada en el cache de render — datos mínimos para dibujar
#[derive(Copy, Clone, Debug)]
pub struct RenderCacheEntry {
    pub world_x: f32,
    pub world_y: f32,
    pub shape_type: u8,
    pub color: u32,
    pub size_x: f32,
    pub layer: u8,
    pub sprite_index: u16, // 0 = sin sprite, >0 = índice en TextureAtlas
}

impl RenderCacheEntry {
    #[inline(always)]
    pub fn new(x: f32, y: f32, shape: u8, color: u32, size_x: f32, layer: u8) -> Self {
        RenderCacheEntry { world_x: x, world_y: y, shape_type: shape, color, size_x, layer, sprite_index: 0 }
    }
    #[inline(always)]
    pub fn new_sprite(x: f32, y: f32, sprite_idx: u16, size_x: f32, layer: u8) -> Self {
        RenderCacheEntry { world_x: x, world_y: y, shape_type: 0, color: 0, size_x, layer, sprite_index: sprite_idx }
    }
}

/// Cache de render con buckets pre-ordenados por capa.
pub struct RenderCache {
    pub buckets: [Vec<RenderCacheEntry>; NUM_RENDER_LAYERS],
    pub dirty: bool,
}

impl RenderCache {
    pub fn new() -> Self {
        let buckets: [Vec<RenderCacheEntry>; NUM_RENDER_LAYERS] =
            std::array::from_fn(|_| Vec::with_capacity(4096));
        RenderCache { buckets, dirty: true }
    }

    pub fn clear(&mut self) {
        for bucket in self.buckets.iter_mut() {
            bucket.clear();
        }
    }

    #[inline(always)]
    pub fn push(&mut self, entry: RenderCacheEntry) {
        let layer = entry.layer.min(NUM_RENDER_LAYERS as u8 - 1) as usize;
        unsafe {
            self.buckets.get_unchecked_mut(layer).push(entry);
        }
    }

    pub fn total_entries(&self) -> usize {
        self.buckets.iter().map(|b| b.len()).sum()
    }

    /// [FASE 8]: Reconstruye el cache desde el mundo ECS con sprite_index
    pub fn rebuild_from_world(&mut self, world: &hecs::World) {
        self.clear();

        // Zonas (capa 1)
        for (_entity, (pos, zone)) in world.query::<(&Position, &ZoneComponent)>().iter() {
            if zone.density > 0 {
                let zc = zone_color(zone.zone_type);
                let zs = zone_sprite(zone.zone_type);
                self.push(RenderCacheEntry {
                    world_x: pos.x, world_y: pos.y,
                    shape_type: 0,
                    color: zc,
                    size_x: 1.0,
                    layer: LAYER_ZONES,
                    sprite_index: zs,
                });
            }
        }

        // Edificios y construcciones (capa 2-3)
        for (_entity, (pos, renderable)) in world.query::<(&Position, &Renderable)>().iter() {
            if renderable.layer >= 2 && renderable.layer <= 3 {
                self.push(RenderCacheEntry {
                    world_x: pos.x, world_y: pos.y,
                    shape_type: renderable.shape_type,
                    color: renderable.color,
                    size_x: renderable.size_x,
                    layer: renderable.layer as u8,
                    sprite_index: renderable.sprite_index,
                });
            }
        }

        // Tráfico (capa 4)
        for (_entity, (pos, renderable)) in world.query::<(&Position, &Renderable)>().iter() {
            if renderable.layer >= 4 {
                self.push(RenderCacheEntry {
                    world_x: pos.x, world_y: pos.y,
                    shape_type: renderable.shape_type,
                    color: renderable.color,
                    size_x: renderable.size_x,
                    layer: renderable.layer as u8,
                    sprite_index: renderable.sprite_index,
                });
            }
        }
        self.dirty = false;
    }

    #[inline]
    pub fn iter_layers(&self) -> RenderCacheIter<'_> {
        RenderCacheIter {
            cache: self,
            current_layer: 0,
            current_idx: 0,
        }
    }
}

pub struct RenderCacheIter<'a> {
    cache: &'a RenderCache,
    current_layer: usize,
    current_idx: usize,
}

impl<'a> Iterator for RenderCacheIter<'a> {
    type Item = &'a RenderCacheEntry;

    fn next(&mut self) -> Option<&'a RenderCacheEntry> {
        loop {
            if self.current_layer >= NUM_RENDER_LAYERS {
                return None;
            }
            let bucket = &self.cache.buckets[self.current_layer];
            if self.current_idx < bucket.len() {
                let entry = &bucket[self.current_idx];
                self.current_idx += 1;
                return Some(entry);
            }
            self.current_layer += 1;
            self.current_idx = 0;
        }
    }
}

// ---------------------------------------------------------------------------
// COLORES Y SPRITES POR TIPO (centralizados para consistencia)
// ---------------------------------------------------------------------------

#[inline(always)]
pub fn building_color(btype: BuildingType) -> u32 {
    match btype {
        BuildingType::House => 0xFF_C4_7B_4A,
        BuildingType::Apartment => 0xFF_B0_BEC5,
        BuildingType::Shop => 0xFF_26_C6_DA,
        BuildingType::Office => 0xFF_78_90_9C,
        BuildingType::Factory => 0xFF_8D_6E_63,
        BuildingType::Farm => 0xFF_8B_C3_4A,
        BuildingType::Hospital => 0xFF_F4_81_81,
        BuildingType::School => 0xFF_FF_D5_4F,
        BuildingType::Police => 0xFF_42_45_E8,
    }
}

/// Índices de sprite del Roguelike Modern City spritesheet.
/// Los edificios están en las filas 4-8 del spritesheet (~30 tiles por fila).
#[inline(always)]
pub fn building_sprite(btype: BuildingType) -> u16 {
    const BUILDING_BASE: u16 = 60;
    match btype {
        BuildingType::House      => BUILDING_BASE + 0,
        BuildingType::Apartment  => BUILDING_BASE + 5,
        BuildingType::Shop       => BUILDING_BASE + 10,
        BuildingType::Office     => BUILDING_BASE + 15,
        BuildingType::Factory    => BUILDING_BASE + 20,
        BuildingType::Farm       => BUILDING_BASE + 25,
        BuildingType::Hospital   => BUILDING_BASE + 30,
        BuildingType::School     => BUILDING_BASE + 35,
        BuildingType::Police     => BUILDING_BASE + 40,
    }
}

#[inline(always)]
pub fn zone_color(ztype: ZoneType) -> u32 {
    match ztype {
        ZoneType::Residential => 0x44_66_BB_6A,
        ZoneType::Commercial => 0x44_42_A5_F5,
        ZoneType::Industrial => 0x44_EF_5350,
        ZoneType::Agricultural => 0x44_9C_CC_65,
        ZoneType::Road => 0x44_55_55_55,
        ZoneType::Park => 0x44_4C_AF_50,
    }
}

